    final int? CONFIGOffset = _CONFIG?.getOrCreateOffset(fbBuilder);
    final int? BATCH_REQUESTOffset = _BATCH_REQUEST?.getOrCreateOffset(fbBuilder);
    final int? BATCH_RESPONSEOffset = _BATCH_RESPONSE?.getOrCreateOffset(fbBuilder);
    final int? RESULTSOffset = _RESULTS == null ? null
        : fbBuilder.writeListOfStructs(_RESULTS!);
    final int? TIME_RANGE_RESULTSOffset = _TIME_RANGE_RESULTS == null ? null
        : fbBuilder.writeListOfStructs(_TIME_RANGE_RESULTS!);
    fbBuilder.startTable(5);
    fbBuilder.addOffset(0, CONFIGOffset);
    fbBuilder.addOffset(1, BATCH_REQUESTOffset);
    fbBuilder.addOffset(2, BATCH_RESPONSEOffset);
    fbBuilder.addOffset(3, RESULTSOffset);
    fbBuilder.addOffset(4, TIME_RANGE_RESULTSOffset);
    return fbBuilder.endTable();
  }

  /// Convenience method to serialize to byte list.
  @override
  Uint8List toBytes([String? fileIdentifier]) {
    final fbBuilder = fb.Builder(deduplicateTables: false);
    fbBuilder.finish(finish(fbBuilder), fileIdentifier);
    return fbBuilder.buffer;
  }
